#
# Provides SecretService: a wrapper around the org.freedesktop.secrets
# Secret Service protocol using Gio.DBusProxy for correct interface
# negotiation.  Works with any compliant implementation: KeePassXC,
# GNOME Keyring, KWallet Secret Service bridge, etc.
#
# Usage
# -----
#   from kwin_lib.secret_service import SecretService
#
#   with SecretService() as ss:
#       password = ss.get_password("MyEntryTitle")
#       items    = ss.list_items()    # [(label, attrs_dict), ...]
#
# get_password(key) finds the item whose Label exactly matches *key* (the
# entry title as shown in the Secret Service provider) and returns the secret
# as a UTF-8 string.  Nothing is cached — each call fetches fresh from the
# provider.
#
# list_items() returns all items in the default collection as a list of
# (label, attributes_dict) tuples, sorted by label.  No secrets are fetched.
#
# D-Bus interfaces used (all via Gio.DBusProxy)
# -----------------------------------------------
#   org.freedesktop.secrets.Service    — OpenSession, Unlock
#   org.freedesktop.secrets.Collection — Items property
#   org.freedesktop.secrets.Item       — Label, Attributes; GetSecret
#   org.freedesktop.secrets.Session    — Close
#   org.freedesktop.secrets.Prompt     — Prompt method, Completed signal
#
# The "plain" algorithm is used for the encryption session.  This is
# universally supported and appropriate for local IPC — the session bus
# is per-user and not network-accessible.
