from __future__ import annotations

from typing import Any

from gi.repository import GLib, Gio


# ── D-Bus constants ───────────────────────────────────────────────────────────

SS_BUS     = "org.freedesktop.secrets"
SS_PATH    = "/org/freedesktop/secrets"
SS_SERVICE = "org.freedesktop.Secret.Service"
SS_COLL    = "org.freedesktop.Secret.Collection"
SS_ITEM    = "org.freedesktop.Secret.Item"
SS_SESSION = "org.freedesktop.Secret.Session"
SS_PROMPT  = "org.freedesktop.Secret.Prompt"

# "default" is a well-known alias for whichever collection the Secret Service
# implementation has designated as the default.
DEFAULT_COLLECTION = "/org/freedesktop/secrets/aliases/default"


# ── Proxy factory and helpers ─────────────────────────────────────────────────

def _proxy(iface: str, path: str) -> Gio.DBusProxy:
    """
    Create a synchronous Gio.DBusProxy for the given interface and path.
    NONE flags allow the proxy to work even if the provider does not export
    full introspection data for every sub-object.
    """
    return Gio.DBusProxy.new_for_bus_sync(
        Gio.BusType.SESSION,
        Gio.DBusProxyFlags.NONE,
        None,       # GDBusInterfaceInfo — None: no pre-validation
        SS_BUS,
        path,
        iface,
        None,       # GCancellable
    )


def _call(proxy: Gio.DBusProxy,
          method: str,
          args: GLib.Variant) -> GLib.Variant:
    """Synchronous method call on a DBusProxy."""
    return proxy.call_sync(
        method, args,
        Gio.DBusCallFlags.NONE, -1, None,
    )


def _prop(proxy: Gio.DBusProxy, name: str) -> Any:
    """
    Read a property from a DBusProxy.
    Tries the proxy cache first; falls back to a live Properties.Get call.
    """
    cached = proxy.get_cached_property(name)
    if cached is not None:
        return cached.unpack()
    result = proxy.call_sync(
        "org.freedesktop.DBus.Properties.Get",
        GLib.Variant("(ss)", (proxy.get_interface_name(), name)),
        Gio.DBusCallFlags.NONE, -1, None,
    )
    return result[0]


def _prompt_if_needed(prompt_path: str) -> None:
    """
    If prompt_path is not '/', trigger a user-visible unlock prompt and wait
    for it to complete.  Used when the collection is locked.
    """
    if prompt_path == "/":
        return

    conn   = Gio.bus_get_sync(Gio.BusType.SESSION, None)
    loop   = GLib.MainLoop()
    result = [None]

    def on_completed(conn2, sender, obj_path, iface, signal, params, user_data):
        dismissed, _res = params
        result[0] = dismissed
        loop.quit()

    sub_id = conn.signal_subscribe(
        SS_BUS, SS_PROMPT, "Completed",
        prompt_path, None,
        Gio.DBusSignalFlags.NONE,
        on_completed, None,
    )
    prompt_proxy = _proxy(SS_PROMPT, prompt_path)
    _call(prompt_proxy, "Prompt", GLib.Variant("(s)", ("",)))
    GLib.timeout_add_seconds(60, loop.quit)
    loop.run()
    conn.signal_unsubscribe(sub_id)

    if result[0]:
        raise RuntimeError("Secret Service unlock prompt was dismissed.")


# ── Availability probe ───────────────────────────────────────────────────────

def is_available() -> bool:
    """
    Return True if the Secret Service is reachable and able to open a session.

    Performs a lightweight round-trip: creates the Service proxy, calls
    OpenSession("plain"), then immediately closes the session.  Returns False
    on any exception.

    This is intentionally a module-level function (not a method) so callers
    can check availability before constructing a SecretService instance — for
    example, from a bash wrapper via the 'check' subcommand in
    kwin_secret_service.py.
    """
    try:
        svc = _proxy(SS_SERVICE, SS_PATH)
        result = _call(
            svc, "OpenSession",
            GLib.Variant("(sv)", ("plain", GLib.Variant("s", ""))),
        )
        session_path = result[1]
        # Close the session we just opened — we only needed the round-trip.
        try:
            sess = _proxy(SS_SESSION, session_path)
            _call(sess, "Close", GLib.Variant("()", ()))
        except Exception:
            pass   # Close failure is harmless; the session will expire anyway
        return True
    except Exception:
        return False


# ── SecretService ─────────────────────────────────────────────────────────────

class SecretService:
    """
    Wrapper around the org.freedesktop.secrets Secret Service protocol.

    Uses Gio.DBusProxy for all D-Bus communication, ensuring correct
    interface negotiation with any compliant Secret Service implementation.

    Use as a context manager or call open() / close() explicitly.
    """

    def __init__(self,
                 collection_path: str = DEFAULT_COLLECTION) -> None:
        self._collection_path = collection_path
        self._svc:     Gio.DBusProxy | None = None   # Service proxy
        self._session: str | None           = None   # Session object path

    # ── Context manager ───────────────────────────────────────────────────────

    def __enter__(self) -> "SecretService":
        self.open()
        return self

    def __exit__(self, *_) -> None:
        self.close()

    # ── Lifecycle ─────────────────────────────────────────────────────────────

    def open(self) -> None:
        """
        Connect to the Secret Service and open an encryption session.

        Raises RuntimeError if the service is unreachable (provider not
        running or Secret Service Integration not enabled).
        """
        try:
            self._svc = _proxy(SS_SERVICE, SS_PATH)
        except Exception as exc:
            raise RuntimeError(
                f"Cannot create Secret Service proxy — is the provider running? ({exc})"
            ) from exc

        try:
            result = _call(
                self._svc, "OpenSession",
                GLib.Variant("(sv)", ("plain", GLib.Variant("s", ""))),
            )
        except Exception as exc:
            raise RuntimeError(
                f"Cannot open Secret Service session ({exc})\n"
                "Ensure the Secret Service provider is running and, for KeePassXC,\n"
                "that Secret Service Integration is enabled:\n"
                "  Tools → Settings → Secret Service Integration"
            ) from exc

        # result is (algorithm_output_variant, session_object_path)
        self._session = result[1]

    def close(self) -> None:
        """Close the encryption session."""
        if self._svc and self._session:
            try:
                sess = _proxy(SS_SESSION, self._session)
                _call(sess, "Close", GLib.Variant("()", ()))
            except Exception:
                pass
        self._svc = self._session = None

    # ── Public API ────────────────────────────────────────────────────────────

    def get_password(self, key: str) -> str:
        """
        Return the secret for the item whose Label exactly matches *key*.

        *key* is the entry title as displayed in the Secret Service provider
        (e.g. the entry title in KeePassXC).  Matching is case-sensitive.

        Raises:
            RuntimeError  — service unavailable, or collection locked
            KeyError      — no item with the given label exists
        """
        self._require_open()
        self._unlock()

        for item_path in self._item_paths():
            try:
                item = _proxy(SS_ITEM, item_path)
                if str(_prop(item, "Label")) == key:
                    return self._fetch_secret(item_path)
            except Exception:
                continue

        raise KeyError(
            f"No Secret Service item found with label {key!r}.\n"
            "Use kwin_secret_service.py list to see available labels.\n"
            "Check that the provider is running and the database is unlocked."
        )

    def list_items(self) -> list[tuple[str, dict[str, str]]]:
        """
        Return all items in the collection as a list of
        (label, attributes_dict) tuples, sorted by label (case-insensitive).

        No secrets are fetched.
        """
        self._require_open()
        self._unlock()

        result = []
        for item_path in self._item_paths():
            try:
                item  = _proxy(SS_ITEM, item_path)
                label = str(_prop(item, "Label"))
                attrs = dict(_prop(item, "Attributes") or {})
                result.append((label, attrs))
            except Exception:
                continue

        result.sort(key=lambda t: t[0].lower())
        return result

    # ── Internal helpers ──────────────────────────────────────────────────────

    def _require_open(self) -> None:
        if self._svc is None or self._session is None:
            raise RuntimeError("SecretService is not open — call open() first.")

    def _unlock(self) -> None:
        """Ensure the collection is unlocked, prompting if necessary."""
        try:
            coll   = _proxy(SS_COLL, self._collection_path)
            locked = _prop(coll, "Locked")
        except Exception as exc:
            raise RuntimeError(
                f"Cannot access collection at {self._collection_path!r}: {exc}\n"
                "Ensure the Secret Service provider is running and unlocked."
            ) from exc

        if not locked:
            return

        result = _call(
            self._svc, "Unlock",
            GLib.Variant("(ao)", ([self._collection_path],)),
        )
        prompt_path = result[1]
        _prompt_if_needed(prompt_path)

        # Re-check after prompt
        coll2 = _proxy(SS_COLL, self._collection_path)
        if _prop(coll2, "Locked"):
            raise RuntimeError(
                "Collection is still locked after unlock attempt. "
                "The provider may be closed or the unlock was cancelled."
            )

    def _item_paths(self) -> list[str]:
        """Return all item object paths in the collection."""
        coll = _proxy(SS_COLL, self._collection_path)
        try:
            return list(_prop(coll, "Items"))
        except Exception as exc:
            raise RuntimeError(
                f"Cannot enumerate items in collection: {exc}"
            ) from exc

    def _fetch_secret(self, item_path: str) -> str:
        """
        Retrieve and decode the secret for one item.
        If the item is locked (KeePassXC requires per-item authorization),
        unlock it via the service — which triggers the KeePassXC approval
        dialog — then retry.
        """
        item = _proxy(SS_ITEM, item_path)
        try:
            result = _call(
                item, "GetSecret",
                GLib.Variant("(o)", (self._session,)),
            )
        except Exception as exc:
            if "IsLocked" not in str(exc):
                raise
            # Item requires explicit unlock (KeePassXC per-item authorization).
            # This is what triggers the KeePassXC "Allow access?" dialog.
            unlock_result = _call(
                self._svc, "Unlock",
                GLib.Variant("(ao)", ([item_path],)),
            )
            prompt_path = unlock_result[1]
            _prompt_if_needed(prompt_path)
            # Retry after authorization
            item   = _proxy(SS_ITEM, item_path)
            result = _call(
                item, "GetSecret",
                GLib.Variant("(o)", (self._session,)),
            )
        # Secret struct: (session_path, parameters, value_bytes, content_type)
        secret_bytes = bytes(result[0][2])
        return secret_bytes.decode("utf-8")
